const results = $json.results;

const extractedUrls = results.map(result=>({
  url:result.url,
  title:result.title,
  description:result.description
}))

return extractedUrls;

const html =$json.data || "";

if(!html){
  throw new Error("No HTML content provide in JSOn data. Ensure input contain valid HTML.")
}

function extractAndCleanContent(html, tag){
  const regex=new RegExp(`<${tag}[^>]*>(.*?)<\/${tag}>`, "gis");
  const matchs =[...html.matchAll(regex)];

  return matchs.map(match =>match[1].replace(/<[^>]*>/g,"").trim())
}

const bodyText = [
  ...extractAndCleanContent(html,"p"),
  ...extractAndCleanContent(html,"span")
];

return{
  bodyText
}

const results = items.map(item => {
  let text = String(item.json.bodyText || "");

  // Remove <script>, <style>, and CSS blocks
  text = text.replace(/<script[\s\S]*?<\/script>/gi, "")
             .replace(/<style[\s\S]*?<\/style>/gi, "")
             .replace(/\.[a-zA-Z0-9_-]+\s*\{[^}]*\}/g, ""); 

  // Remove all HTML tags
  text = text.replace(/<[^>]*>/g, "");

  // Remove leftover CSS/JS inline blocks like @media, @supports
  text = text.replace(/@media[\s\S]*?\{[\s\S]*?\}/gi, "")
             .replace(/@supports[\s\S]*?\{[\s\S]*?\}/gi, "");

  // Decode common HTML entities
  text = text.replace(/&nbsp;/g, " ")
             .replace(/&amp;/g, "&")
             .replace(/&lt;/g, "<")
             .replace(/&gt;/g, ">");

  // Remove excessive whitespace, newlines, commas
  text = text.replace(/\s{2,}/g, " ")
             .replace(/ ,/g, ",")
             .replace(/\n{2,}/g, "\n");

  return text.trim();
});

const separator = "\n\n--- Page Break ---\n\n";

const combinedBodyText = results.filter(Boolean).join(separator);

return [{ json: { combinedBodyText } }];

let text = items[0].json.combinedBodyText || "";

// --- 1. Remove CSS, JSON, boilerplate ---
text = text.replace(/(\.[a-zA-Z0-9_-]+|\#[a-zA-Z0-9_-]+)/g, ""); // .className / #id
text = text.replace(/\{[^}]*\}/g, ""); // { ... }
text = text.replace(/\[[^\]]*\]/g, ""); // [ ... ]
text = text.replace(/@media[^{]*\{[^}]*\}/g, ""); // media queries
text = text.replace(/\s+/g, " ").trim();

// --- 2. Split into chunks (like paragraphs/sentences) ---
let parts = text.split(/(?<=[.!?])\s+/);

// --- 3. Keep only meaningful parts ---
let cleanParts = parts.filter(p => {
  // Skip if too short
  if (p.length < 40) return false;

  // Skip if it's navigation/menu/ads
  if (p.match(/\b(home|login|account|menu|courses|newsletter|skip to content|join our|subscribe)\b/i)) {
    return false;
  }

  // Skip if contains code-like stuff
  if (p.match(/[{};:=]/)) return false;

  return true;
});

// --- 4. Recombine into clean text ---
let finalContent = cleanParts.join(" ");

return [{ json: { finalContent } }];
